import{_ as e,c as t,o as s,ag as p}from"./chunks/framework.ELrfyV9R.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/aehyok/status/2041677992586571985","created":"2026-04-08T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/Hermes Agent 从零手把手安装使用指南.md","filePath":"ai/bookmark/Hermes Agent 从零手把手安装使用指南.md","lastUpdated":1776945928000}'),i={name:"ai/bookmark/Hermes Agent 从零手把手安装使用指南.md"};function r(m,a,n,o,l,h){return s(),t("div",null,a[0]||(a[0]=[p(`<p>Hermes Agent 是 Nous Research 开源的自改进 AI Agent 框架，目前已经拥有31.3K star。而且目前可以通过 OAuth 直连 Claude，不像OpenClaw还需要中间一层联入Claude Code，体验略差。至于Claude 后面会不会也封禁，目前尚不得知了。</p><p>如果你想了解一下它是什么可以看看下面这个链接</p><blockquote><p>9小时</p></blockquote><p>项目开源地址：</p><p><a href="https://github.com/NousResearch/hermes-agent" target="_blank" rel="noreferrer">https://github.com/NousResearch/hermes-agent</a></p><h2 id="_1、安装" tabindex="-1">1、安装 <a class="header-anchor" href="#_1、安装" aria-label="Permalink to &quot;1、安装&quot;">​</a></h2><p><a href="https://hermes-agent.nousresearch.com/docs/getting-started/quickstart" target="_blank" rel="noreferrer">https://hermes-agent.nousresearch.com/docs/getting-started/quickstart</a></p><p>官网上有安装命令，你也可以直接复制我下面的指令。</p><p>首先在电脑上打开终端命令行工具，输入如下命令</p><blockquote><p>注意目前命令支持：Linux、macOS、WSL2（Windows 原生好像还不支持），尽量还要确保本设备Git已可以使用，可以使用git verion命令进行检查</p></blockquote><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 检查git是否可用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 打开终端输入如下命令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bashcurl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/NousResearch/hermes-agent/main/scripts/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>这里我看了一下要安装的东西不少，如果网络不好，可能要多等待一会儿。</p><blockquote><p>比如 Python 、Node.js、ffmpeg 等所有依赖、仓库克隆，并创建全局 hermes 命令</p></blockquote><p><img src="https://pbs.twimg.com/media/HFVdiLFa8AMC0W3?format=jpg&amp;name=large" alt="图像"></p><p>安装完毕之后就可以进行设置了</p><p><img src="https://pbs.twimg.com/media/HFVfkR_bwAAlb0W?format=jpg&amp;name=large" alt="图像"></p><p>这里我选择Quick setup模式</p><p><img src="https://pbs.twimg.com/media/HFVgF2EaoAArp8j?format=jpg&amp;name=large" alt="图像"></p><p>然后进行选择大模型,你可以直接选择Claude、OpenAI等，这里我直接选择OpenAI Codex，这里选择完毕，它直接读取我原来本地的OpenAI Codex的授权配置了，有点方便。</p><p><img src="https://pbs.twimg.com/media/HFVifYta8AAme1M?format=jpg&amp;name=large" alt="图像"></p><p>这里如果选择第二个跳过，然后可以直接终端命令行中输入命令hermes，就可以看到如下界面，直接在命令行中进行聊天了。</p><p>说明我们的Hermes初步安装完毕。</p><p><img src="https://pbs.twimg.com/media/HFVtLVgaYAAIQz6?format=jpg&amp;name=large" alt="图像"></p><p>如果你想继续配置聊天机器人可以重新运行命令</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hermes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>同样会跳转到配置聊天机器人的相关配置</p><h2 id="_2、配置聊天机器人" tabindex="-1">2、配置聊天机器人 <a class="header-anchor" href="#_2、配置聊天机器人" aria-label="Permalink to &quot;2、配置聊天机器人&quot;">​</a></h2><p>上面如果我们没有选择Skip，选择Set up messaging now, 也就是对接IM 聊天工具</p><p><img src="https://pbs.twimg.com/media/HFVjZd4boAAZUlW?format=jpg&amp;name=large" alt="图像"></p><p>这里我就选择最简单的Telegram来进行配对, 看下图的1234就知道需要先到Telegram进行配置了。</p><p>设置完毕再回来设置这个Bot token</p><p><img src="https://pbs.twimg.com/media/HFVnWjAa8AMJC4N?format=jpg&amp;name=large" alt="图像"></p><p>根据上面这个截图的四部开始</p><p><img src="https://pbs.twimg.com/media/HFVoKRBa0AAEYOG?format=jpg&amp;name=large" alt="图像"></p><p>1、打开Telegram，搜索BotFather</p><p>2、输入/newbot，设置两个name</p><p>将我上面标红的HTTP API也就是 Bot token 复制到命令行工具中</p><blockquote><p>注意粘贴后是看不到消息的，直接回车就可以了</p></blockquote><p><img src="https://pbs.twimg.com/media/HFVqp96a8AA01Ud?format=jpg&amp;name=large" alt="图像"></p><p>这个 user IDs就是前面HTTP API 前面的数字部分，同样复制即可</p><p>进入下一步</p><p><img src="https://pbs.twimg.com/media/HFVq-hWa8AIm7W6?format=jpg&amp;name=large" alt="图像"></p><p>安装过OpenClaw的可能都熟悉就是要进行配对了</p><p>那接下来回到Telegram 工具</p><p><img src="https://pbs.twimg.com/media/HFVuEFEa8AAJR8G?format=jpg&amp;name=large" alt="图像"></p><p>点击箭头的链接跳转到聊天机器人</p><p><img src="https://pbs.twimg.com/media/HFVuTUDaAAAttDf?format=jpg&amp;name=large" alt="图像"></p><p>然后复制上面的命令到终端命令行中执行，执行完毕就可以聊天了</p><p><img src="https://pbs.twimg.com/media/HFVzq3qa8AEJbX5?format=jpg&amp;name=large" alt="图像"></p><h2 id="_3、其他机器人配置" tabindex="-1">3、其他机器人配置 <a class="header-anchor" href="#_3、其他机器人配置" aria-label="Permalink to &quot;3、其他机器人配置&quot;">​</a></h2><p>其他聊天机器人同理跟OpenClaw其实没什么区别，详情可以直接参考官网的安装指南，像飞书、企业微信、叮叮等都已支持</p><p><a href="https://hermes-agent.nousresearch.com/docs/user-guide/messaging/" target="_blank" rel="noreferrer">https://hermes-agent.nousresearch.com/docs/user-guide/messaging/</a></p><h2 id="_4、命令行指南" tabindex="-1">4、命令行指南 <a class="header-anchor" href="#_4、命令行指南" aria-label="Permalink to &quot;4、命令行指南&quot;">​</a></h2><p>可直接命令行输入hermes -h查看指南</p><p><img src="https://pbs.twimg.com/media/HFV1uysa8AAn2DU?format=jpg&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HFV13CIa8AA7Fuw?format=jpg&amp;name=large" alt="图像"></p><h2 id="_5、最后" tabindex="-1">5、最后 <a class="header-anchor" href="#_5、最后" aria-label="Permalink to &quot;5、最后&quot;">​</a></h2><p>可以使用命令 hermes doctor 进行检查</p><p><img src="https://pbs.twimg.com/media/HFV2rouaEAA9cHa?format=jpg&amp;name=large" alt="图像"></p><p>还支持从OpenClaw进行迁移配置，很多命令其实跟OpenClaw大同小异。后续将会继续分享关于hermes-agent的精彩内容。</p>`,60)]))}const d=e(i,[["render",r]]);export{c as __pageData,d as default};
